Add-Type -AssemblyName UIAutomationClient; Add-Type -AssemblyName UIAutomationTypes; $vrs = Get-Process VoiceRecorder, SoundRecorder -ErrorAction SilentlyContinue; if ($vrs) { $root = [System.Windows.Automation.AutomationElement]::RootElement; foreach ($vr in $vrs) { $cond = New-Object System.Windows.Automation.PropertyCondition([System.Windows.Automation.AutomationElement]::ProcessIdProperty, $vr.Id); $win = $root.FindFirst([System.Windows.Automation.TreeScope]::Children, $cond); if (-not $win) { $condW = New-Object System.Windows.Automation.PropertyCondition([System.Windows.Automation.AutomationElement]::ControlTypeProperty, [System.Windows.Automation.ControlType]::Window); $and = New-Object System.Windows.Automation.AndCondition($cond, $condW); $win = $root.FindFirst([System.Windows.Automation.TreeScope]::Descendants, $and) }; if ($win) { $btns = $win.FindAll([System.Windows.Automation.TreeScope]::Descendants, (New-Object System.Windows.Automation.PropertyCondition([System.Windows.Automation.AutomationElement]::ControlTypeProperty, [System.Windows.Automation.ControlType]::Button))); foreach ($btn in $btns) { "$($btn.Current.Name)" } } } }
